import{_ as a,o,c as t,a2 as r}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Introdução","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/introduction.md","filePath":"pt/guide/introduction.md"}'),s={name:"pt/guide/introduction.md"};function i(d,e,n,c,l,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="introducao" tabindex="-1">Introdução <a class="header-anchor" href="#introducao" aria-label="Permalink to &quot;Introdução&quot;">​</a></h1><h2 id="o-que-e-o-clearance" tabindex="-1">O que é o Clearance? <a class="header-anchor" href="#o-que-e-o-clearance" aria-label="Permalink to &quot;O que é o Clearance?&quot;">​</a></h2><p>O Clearance é um painel de administração pronto a usar para aplicações Laravel, construído sobre o <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. Acrescenta um painel Livewire 4 + Flux UI para gerir permissões, papéis, guards e configurações, mais uma camada de autorização contextual e tetos de papéis - instalável com um único comando artisan, sem alterar qualquer tabela do Spatie.</p><p>O Clearance oferece-lhe:</p><ul><li><strong>Painel de administração</strong> para Permissões, Papéis, Guards, Configurações e um Painel de Controle - use as rotas pré-construídas ou incorpore cada componente Livewire individualmente.</li><li><strong>Autorização contextual</strong> - conceda um papel ou permissão delimitado a uma instância de modelo específica (uma Store, um Tenant, um Project), com <code>$user-&gt;canIn()</code>, diretivas Blade <code>@canin</code>/<code>@hasrolein</code>, e um <code>ContextService</code> para uso fora do modelo User.</li><li><strong>Papéis-teto</strong> - um papel pode declarar um papel principal cujo conjunto de permissões atua como limite superior; um papel filho nunca pode exceder o seu papel principal, aplicado automaticamente a cada gravação.</li><li><strong>Permissões de escrita granulares</strong> - uma permissão delegável <code>clearance-{section}-write</code> por secção do painel, para que possa atribuir &quot;gerir papéis&quot; sem também atribuir &quot;gerir configurações.&quot;</li><li><strong>Super Admin</strong> com um bypass global e opcional da Gate, deteção de aliases para papéis do tipo administrador já existentes, e promoção segura e não destrutiva.</li><li><strong>Módulo de Utilizadores</strong> (opcional) - atribua papéis globalmente ou a um contexto específico, mais substituições de permissão por contexto, a partir de um painel por utilizador.</li><li><strong>Painel de Configurações</strong> - nome de exibição, descrição, ícone SVG sanitizado e cor por papel/guard; um papel padrão configurável com atribuição automática e atribuição em massa.</li><li><strong>Gestão de Guards</strong> - guards apoiados em base de dados, injetados em <code>auth.guards</code> no arranque, restritos a um conjunto de drivers em lista de permissões.</li><li><strong>9 idiomas incluídos</strong> (ar, en, es, fr, hi, it, pt, ru, zh), testados quanto à paridade de chaves.</li><li><strong>Pontos de extensibilidade</strong> - trait <code>HasClearance</code>, trait <code>HasPermissionGroups</code>, contrato <code>ClearanceContextable</code>, componentes Blade reutilizáveis.</li><li><strong>Sanitização de SVG</strong> - todo o ícone fornecido pelo utilizador passa por um sanitizador com lista de permissões antes do armazenamento e no momento da renderização.</li><li><strong>Reforçado em segurança</strong> - tetos contra escalonamento de privilégios em todos os caminhos de concessão de permissões, substituições de contexto com autoridade de negação, namespace <code>clearance-*</code> protegido. Ver <a href="/clearance-docs/pt/guide/security.html">Segurança</a>.</li></ul><h2 id="relacao-com-o-spatie-laravel-permission" tabindex="-1">Relação com o spatie/laravel-permission <a class="header-anchor" href="#relacao-com-o-spatie-laravel-permission" aria-label="Permalink to &quot;Relação com o spatie/laravel-permission&quot;">​</a></h2><p>O Clearance não substitui o pacote de permissões do Spatie - é uma camada de UI e autorização sobre ele. Os papéis e permissões continuam a ser os modelos <code>Role</code> e <code>Permission</code> do Spatie, continuando a ser guardados nas tabelas <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> e <code>role_has_permissions</code> do Spatie. O Clearance nunca altera essas tabelas. Tudo o que o Clearance acrescenta - metadados de exibição, escopo de papel, tetos, atribuições contextuais, substituições por contexto - reside no seu próprio conjunto de tabelas <code>clr_*</code>. Ver <a href="/clearance-docs/pt/guide/architecture.html">Arquitetura</a> para a descrição completa.</p><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependência</th><th>Versão</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="conceitos-chave" tabindex="-1">Conceitos-chave <a class="header-anchor" href="#conceitos-chave" aria-label="Permalink to &quot;Conceitos-chave&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Conceito</th><th>Resumo</th></tr></thead><tbody><tr><td>Permissão</td><td>Uma permissão do Spatie que segue a convenção de nomenclatura <code>group-action</code> (ex. <code>orders-create</code>). Concede uma habilidade.</td></tr><tr><td>Escopo do papel</td><td>Todo o papel é <code>global</code> (atribuído diretamente, aplica-se em todo o lado) ou <code>contextual</code> (vinculado a tipos de modelo específicos, apenas atribuível dentro de uma instância de contexto).</td></tr><tr><td>Papel-teto</td><td>Um papel pode declarar um papel principal cujo conjunto de permissões é um limite superior - o filho nunca o pode exceder.</td></tr><tr><td>Contexto</td><td>Uma instância de modelo (uma Store, um Tenant, um Project) à qual um papel ou uma substituição de permissão pode ser delimitado.</td></tr><tr><td>Substituição</td><td>Uma concessão ou negação de permissão <code>forced_on</code>/<code>forced_off</code> por utilizador, por contexto - uma negação ganha sempre.</td></tr></tbody></table><p>Cada um destes conceitos tem uma página completa: <a href="/clearance-docs/pt/features/permissions.html">Permissões</a>, <a href="/clearance-docs/pt/features/roles.html">Papéis</a>, <a href="/clearance-docs/pt/features/contextual-authorization.html">Autorização Contextual</a>, <a href="/clearance-docs/pt/features/users.html">Utilizadores</a>, <a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a>.</p><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h2><p>Pronto para instalar o Clearance? Continue para o <a href="/clearance-docs/pt/guide/installation.html">guia de Instalação</a>.</p>',14)])])}const h=a(s,[["render",i]]);export{m as __pageData,h as default};
